-- ADR-0001: backfill external_id, kickoff_at from football-data.org
-- Generated 2026-05-28 from /competitions/WC/matches response.
-- 48 teams + 72 group matches + 32 knockout matches

-- Allow CANCELLED status (FD returns CANCELLED; Q10 lifecycle policy treats as terminal)
ALTER TABLE public.matches DROP CONSTRAINT matches_status_check;
ALTER TABLE public.matches ADD CONSTRAINT matches_status_check
  CHECK (status = ANY (ARRAY['SCHEDULED','LIVE','FINISHED','POSTPONED','CANCELLED']));

